List<String> names = List.of("Alice", "Bob", "Charlie");

// toList()
List<String> list = names.stream()
    .filter(s -> s.length() > 3)
    .collect(Collectors.toList());
System.out.println(list); // [Alice, Charlie]

// toSet()
Set<Integer> lengths = names.stream()
    .map(String::length)
    .collect(Collectors.toSet());
System.out.println(lengths); // [3, 5, 7]

// toMap()
Map<String, Integer> nameLength = names.stream()
    .collect(Collectors.toMap(
        s -> s,           // keyMapper
        String::length    // valueMapper
    ));
System.out.println(nameLength);
// {Alice=5, Bob=3, Charlie=7}

// toMap() 重複キーの処理
List<String> words = List.of("AA", "BB", "AB");
Map<Character, String> map = words.stream()
    .collect(Collectors.toMap(
        s -> s.charAt(0),       // キー
        s -> s,                 // 値
        (v1, v2) -> v1 + "," + v2  // 重複時のマージ
    ));
System.out.println(map); // {A=AA,AB, B=BB}

List<String> names = List.of("Alice", "Bob", "Charlie");

// 区切り文字なし
String s1 = names.stream().collect(Collectors.joining());
System.out.println(s1); // AliceBobCharlie

// カンマ区切り
String s2 = names.stream().collect(Collectors.joining(", "));
System.out.println(s2); // Alice, Bob, Charlie

// 区切り文字 + 接頭辞 + 接尾辞
String s3 = names.stream()
    .collect(Collectors.joining(", ", "[", "]"));
System.out.println(s3); // [Alice, Bob, Charlie]

// 数値のStreamを文字列に変換してjoin
String s4 = List.of(1, 2, 3).stream()
    .map(String::valueOf)
    .collect(Collectors.joining("-"));
System.out.println(s4); // 1-2-3

List<String> names = List.of("Alice", "Bob", "Charlie", "Anna", "Brian");

// groupingBy: 頭文字でグループ化
Map<Character, List<String>> grouped = names.stream()
    .collect(Collectors.groupingBy(s -> s.charAt(0)));
System.out.println(grouped);
// {A=[Alice, Anna], B=[Bob, Brian], C=[Charlie]}

// groupingBy + counting: グループごとの件数
Map<Character, Long> counts = names.stream()
    .collect(Collectors.groupingBy(
        s -> s.charAt(0),
        Collectors.counting()
    ));
System.out.println(counts); // {A=2, B=2, C=1}

// partitioningBy: 条件で二分
Map<Boolean, List<String>> partitioned = names.stream()
    .collect(Collectors.partitioningBy(s -> s.length() > 3));
System.out.println(partitioned);
// {false=[Bob], true=[Alice, Charlie, Anna, Brian]}

List<String> names = List.of("Alice", "Bob", "Charlie", "Anna");

// summarizingInt: 統計情報
IntSummaryStatistics stats = names.stream()
    .collect(Collectors.summarizingInt(String::length));
System.out.println("Count: " + stats.getCount());     // 4
System.out.println("Sum: " + stats.getSum());         // 20
System.out.println("Min: " + stats.getMin());         // 3
System.out.println("Max: " + stats.getMax());         // 7
System.out.println("Avg: " + stats.getAverage());     // 5.0

// groupingBy + summingInt
Map<Character, Integer> sumByInitial = names.stream()
    .collect(Collectors.groupingBy(
        s -> s.charAt(0),
        Collectors.summingInt(String::length)
    ));
System.out.println(sumByInitial); // {A=9, B=3, C=7}

