// of(): 非nullの値を指定
Optional<String> opt1 = Optional.of("Hello");
System.out.println(opt1); // Optional[Hello]

// of()にnullを渡すとNPE
try {
    Optional<String> opt2 = Optional.of(null);
} catch (NullPointerException e) {
    System.out.println("NPE発生"); // NPE発生
}

// ofNullable(): nullかもしれない値を指定
Optional<String> opt3 = Optional.ofNullable("World");
System.out.println(opt3); // Optional[World]

Optional<String> opt4 = Optional.ofNullable(null);
System.out.println(opt4); // Optional.empty

// empty(): 空のOptional
Optional<String> opt5 = Optional.empty();
System.out.println(opt5); // Optional.empty

Optional<String> opt = Optional.of("Java");
Optional<String> empty = Optional.empty();

// isPresent()
System.out.println(opt.isPresent());   // true
System.out.println(empty.isPresent()); // false

// ifPresent(): 値がある場合のみ実行
opt.ifPresent(s -> System.out.println("値: " + s));
// 出力: 値: Java

empty.ifPresent(s -> System.out.println("値: " + s));
// 何も出力されない

// get(): 値を取得
System.out.println(opt.get()); // Java

try {
    empty.get();
} catch (NoSuchElementException e) {
    System.out.println("値なし"); // 値なし
}

Optional<String> opt = Optional.of("Java");
Optional<String> empty = Optional.empty();

// orElse(): デフォルト値を指定
System.out.println(opt.orElse("default"));   // Java
System.out.println(empty.orElse("default")); // default

// orElseGet(): Supplierでデフォルト値を生成
System.out.println(empty.orElseGet(() -> "generated"));
// 出力: generated

// orElseThrow(): 値がなければ例外
System.out.println(opt.orElseThrow()); // Java
try {
    empty.orElseThrow(() -> new IllegalArgumentException("値なし"));
} catch (IllegalArgumentException e) {
    System.out.println(e.getMessage()); // 値なし
}

// orElse vs orElseGet の違い
// ※ heavyMethod() は時間のかかる処理を表す仮のメソッドです
Optional<String> present = Optional.of("A");
present.orElse(heavyMethod());      // heavyMethodは常に実行される
present.orElseGet(() -> heavyMethod()); // heavyMethodは実行されない

Optional<String> opt = Optional.of("Hello");

// map: 値を変換
Optional<Integer> len = opt.map(String::length);
System.out.println(len); // Optional[5]

// 空のOptionalにmap
Optional<Integer> empty = Optional.<String>empty()
    .map(String::length);
System.out.println(empty); // Optional.empty

// flatMap: Optionalを返す関数に使用
Optional<String> result = opt.flatMap(
    s -> s.length() > 3 ? Optional.of(s.toUpperCase()) : Optional.empty()
);
System.out.println(result); // Optional[HELLO]

// mapだと二重ラップされる
Optional<Optional<String>> doubled = opt.map(
    s -> Optional.of(s.toUpperCase())
);
System.out.println(doubled); // Optional[Optional[HELLO]]

